7	#include <algorithm>
8	#include <utility>
9	#include <rime/candidate.h>
10	#include <rime/context.h>
11	#include <rime/menu.h>
12	#include <rime/segmentation.h>
13	
14	namespace rime {
15	
16	const string kSelectedBeforeEditing = "selected_before_editing";
17	
18	bool Context::Commit() {
19	  if (!IsComposing())
20	    return false;
21	  // notify the engine and interesting components
22	  commit_notifier_(this);
23	  // start over
24	  Clear();
25	  return true;
26	}
27	
28	string Context::GetCommitText() const {
29	  if (get_option("dumb"))
30	    return string();
31	  return composition_.GetCommitText();
32	}
33	
34	string Context::GetScriptText() const {
35	  return composition_.GetScriptText();
36	}
37	
38	static const string kCaretSymbol("\xe2\x80\xb8");  // U+2038 ‸ CARET
39	
40	string Context::GetSoftCursor() const {
41	  return get_option("soft_cursor") ? kCaretSymbol : string();
42	}
43	
44	Preedit Context::GetPreedit() const {
45	  return composition_.GetPreedit(input_, caret_pos_, GetSoftCursor());
46	}
47	
48	bool Context::IsComposing() const {
49	  return !input_.empty() || !composition_.empty();
50	}
51	
52	bool Context::HasMenu() const {
53	  if (composition_.empty())
54	    return false;
55	  const auto& menu(composition_.back().menu);
56	  return menu && !menu->empty();
57	}
58	
59	an<Candidate> Context::GetSelectedCandidate() const {
60	  if (composition_.empty())
61	    return nullptr;
62	  return composition_.back().GetSelectedCandidate();
63	}
64	
65	bool Context::PushInput(char ch) {
66	  if (caret_pos_ >= input_.length()) {
67	    input_.push_back(ch);
68	    caret_pos_ = input_.length();
69	  } else {
70	    input_.insert(caret_pos_, 1, ch);
71	    ++caret_pos_;
72	  }
73	  update_notifier_(this);
74	  return true;
75	}
76	
77	bool Context::PushInput(const string& str) {
78	  if (caret_pos_ >= input_.length()) {
79	    input_ += str;
80	    caret_pos_ = input_.length();
81	  } else {
82	    input_.insert(caret_pos_, str);
83	    caret_pos_ += str.length();
84	  }
85	  update_notifier_(this);
86	  return true;
87	}
88	
89	bool Context::PopInput(size_t len) {
90	  if (caret_pos_ < len)
91	    return false;
92	  caret_pos_ -= len;
93	  input_.erase(caret_pos_, len);
94	  update_notifier_(this);
95	  return true;
96	}
97	
98	bool Context::DeleteInput(size_t len) {
99	  if (caret_pos_ + len > input_.length())
100	    return false;
101	  input_.erase(caret_pos_, len);
102	  update_notifier_(this);
103	  return true;
104	}
105	
106	void Context::Clear() {
107	  input_.clear();
108	  caret_pos_ = 0;
109	  composition_.clear();
110	  update_notifier_(this);
111	}
112	
113	void Context::AbortComposition() {
114	  Clear();
115	  abort_notifier_(this);
116	}
117	
118	bool Context::Select(size_t index) {
119	  if (composition_.empty())
120	    return false;
121	  Segment& seg(composition_.back());
122	  if (auto cand = seg.GetCandidateAt(index)) {
123	    seg.selected_index = index;
124	    seg.status = Segment::kSelected;
125	    DLOG(INFO) << "Selected: '" << cand->text() << "', index = " << index;
126	    select_notifier_(this);
127	    return true;
128	  }
129	  return false;
130	}
131	
132	bool Context::Highlight(size_t index) {
133	  if (composition_.empty() || !composition_.back().menu)
134	    return false;
135	  Segment& seg(composition_.back());
136	  size_t candidate_count = seg.menu->Prepare(index + 1);
137	  size_t new_index =
138	      candidate_count > 0 ? (std::min)(candidate_count - 1, index) : 0;
139	  size_t previous_index = seg.selected_index;
140	  if (previous_index == new_index) {
141	    DLOG(INFO) << "selection has not changed, currently at " << new_index;
142	    return false;
143	  }
144	  seg.selected_index = new_index;
145	  update_notifier_(this);
146	  DLOG(INFO) << "selection changed from: " << previous_index
147	             << " to: " << new_index;
148	  return true;
149	}
150	
151	bool Context::DeleteCandidate(size_t index) {
152	  if (composition_.empty())
153	    return false;
154	  Segment& seg(composition_.back());
155	  seg.selected_index = index;
156	  DLOG(INFO) << "Deleting candidate: " << seg.GetSelectedCandidate()->text();
157	  delete_notifier_(this);
158	  return true;  // CAVEAT: this doesn't mean anything is deleted for sure
159	}
160	
161	bool Context::DeleteCurrentSelection() {
162	  if (composition_.empty())
163	    return false;
164	  Segment& seg(composition_.back());
165	  return DeleteCandidate(seg.selected_index);
166	}
167	
168	bool Context::ConfirmCurrentSelection() {
169	  if (composition_.empty())
170	    return false;
171	  Segment& seg(composition_.back());
172	  seg.status = Segment::kSelected;
173	  if (auto cand = seg.GetSelectedCandidate()) {
174	    DLOG(INFO) << "Confirmed: '" << cand->text()
175	               << "', selected_index = " << seg.selected_index;
176	  } else {
177	    if (seg.end == seg.start) {
178	      // fluid_editor will confirm the whole sentence
179	      return false;
180	    }
181	    // confirm raw input
182	  }
183	  select_notifier_(this);
184	  return true;
185	}
186	
187	void Context::BeginEditing() {
188	  for (auto it = composition_.rbegin(); it != composition_.rend(); ++it) {
189	    if (it->status > Segment::kSelected) {
190	      return;
191	    }
192	    if (it->status == Segment::kSelected) {
193	      it->tags.insert(kSelectedBeforeEditing);
194	      return;
195	    }
196	  }
197	}
198	
199	bool Context::ConfirmPreviousSelection() {
200	  BeginEditing();
201	  return false;
202	}
203	
204	bool Context::ReopenPreviousSegment() {
205	  if (composition_.Trim()) {
206	    if (!composition_.empty() &&
207	        composition_.back().status >= Segment::kSelected) {
208	      composition_.back().Reopen(caret_pos());
209	    }
210	    update_notifier_(this);
211	    return true;
212	  }
213	  return false;
214	}
215	
216	bool Context::ClearPreviousSegment() {
217	  if (composition_.empty())
218	    return false;
219	  size_t where = composition_.back().start;
220	  if (where >= input_.length())
221	    return false;
222	  set_input(input_.substr(0, where));
223	  return true;
224	}
225	
226	bool Context::ReopenPreviousSelection() {
227	  for (auto it = composition_.rbegin(); it != composition_.rend(); ++it) {
228	    if (it->status > Segment::kSelected)
229	      return false;
230	    if (it->status == Segment::kSelected) {
231	      // do not reopen the previous selection after editing input.
232	      if (it->tags.count(kSelectedBeforeEditing) != 0) {
233	        return false;
234	      }
235	      while (it != composition_.rbegin()) {
236	        composition_.pop_back();
237	      }
238	      it->Reopen(caret_pos());
239	      update_notifier_(this);
240	      return true;
241	    }
242	  }
243	  return false;
244	}
245	
246	bool Context::ClearNonConfirmedComposition() {
247	  bool reverted = false;
248	  while (!composition_.empty() &&
249	         composition_.back().status < Segment::kSelected) {
250	    composition_.pop_back();
251	    reverted = true;
252	  }
253	  if (reverted) {
254	    composition_.Forward();
255	    DLOG(INFO) << "composition: " << composition_.GetDebugText();
256	  }
257	  return reverted;
258	}
259	
260	bool Context::RefreshNonConfirmedComposition() {
261	  if (ClearNonConfirmedComposition()) {
262	    update_notifier_(this);
263	    return true;
264	  }
265	  return false;
266	}
267	
268	void Context::set_caret_pos(size_t caret_pos) {
269	  if (caret_pos > input_.length())
270	    caret_pos_ = input_.length();
271	  else
272	    caret_pos_ = caret_pos;
273	  update_notifier_(this);
274	}
275	
276	void Context::set_composition(Composition&& comp) {
277	  composition_ = std::move(comp);
278	}
279	
280	void Context::set_input(const string& value) {
281	  input_ = value;
282	  caret_pos_ = input_.length();
283	  update_notifier_(this);
284	}
285	
286	void Context::set_option(const string& name, bool value) {
287	  options_[name] = value;
288	  DLOG(INFO) << "Context::set_option " << name << " = " << value;
289	  option_update_notifier_(this, name);
290	}
291	
292	bool Context::get_option(const string& name) const {
293	  auto it = options_.find(name);
294	  if (it != options_.end())
295	    return it->second;
296	  else
297	    return false;
298	}
299	
300	void Context::set_property(const string& name, const string& value) {
301	  properties_[name] = value;
302	  property_update_notifier_(this, name);
303	}
304	
305	string Context::get_property(const string& name) const {
306	  auto it = properties_.find(name);
307	  if (it != properties_.end())
308	    return it->second;
309	  else
310	    return string();
311	}
312	
313	void Context::ClearTransientOptions() {
314	  DLOG(INFO) << "Context::ClearTransientOptions";
315	  auto opt = options_.lower_bound("_");
316	  while (opt != options_.end() && !opt->first.empty() && opt->first[0] == '_') {
317	    DLOG(INFO) << "cleared opption: " << opt->first;
318	    options_.erase(opt++);
319	  }
320	  auto prop = properties_.lower_bound("_");
321	  while (prop != properties_.end() && !prop->first.empty() &&
322	         prop->first[0] == '_') {
323	    properties_.erase(prop++);
324	  }
325	}
326	
327	}  // namespace rime
328

