20	void CommitHistory::Push(const KeyEvent& key_event) {
21	  if (key_event.modifier() == 0) {
22	    if (key_event.keycode() == XK_BackSpace ||
23	        key_event.keycode() == XK_Return) {
24	      clear();
25	    } else if (key_event.keycode() >= 0x20 && key_event.keycode() <= 0x7e) {
26	      // printable ascii character
27	      Push(CommitRecord(key_event.keycode()));
28	    }
29	  }
30	}
31	
32	void CommitHistory::Push(const Composition& composition, const string& input) {
33	  CommitRecord* last = NULL;
34	  size_t end = 0;
35	  for (const Segment& seg : composition) {
36	    if (auto cand = seg.GetSelectedCandidate()) {
37	      if (last && last->type == cand->type()) {
38	        // join adjacent text of same type
39	        last->text += cand->text();
40	      } else {
41	        // new record
42	        Push({cand->type(), cand->text()});
43	        last = &back();
44	      }
45	      if (seg.status >= Segment::kConfirmed) {
46	        // terminate a record by confirmation
47	        last = NULL;
48	      }
49	      end = cand->end();
50	    } else {
51	      // no translation for the segment
52	      Push({"raw", input.substr(seg.start, seg.end - seg.start)});
53	      end = seg.end;
54	    }
55	  }
56	  if (input.length() > end) {
57	    Push({"raw", input.substr(end)});
58	  }
59	}
